CREATE TABLE documents(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),owner_customer_id uuid NOT NULL REFERENCES customers(id),asset_id uuid REFERENCES assets(id),passport_id uuid REFERENCES passports(id),kind text NOT NULL,name text NOT NULL,mime_type text NOT NULL,size_bytes bigint NOT NULL CHECK(size_bytes>0),content_hash char(64) NOT NULL,storage_key text NOT NULL,classification text NOT NULL CHECK(classification IN('private','customer_shared','professional_shared','resale_public')),retention_until timestamptz,version integer NOT NULL DEFAULT 1,created_by uuid NOT NULL,created_at timestamptz NOT NULL,UNIQUE(tenant_id,storage_key,version));
CREATE TABLE consents(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),customer_id uuid NOT NULL REFERENCES customers(id),grantee_organization_id uuid NOT NULL REFERENCES organizations(id),purpose text NOT NULL,scopes text[] NOT NULL,asset_ids uuid[] NOT NULL,granted_at timestamptz NOT NULL,expires_at timestamptz NOT NULL,revoked_at timestamptz,proof char(64) NOT NULL,created_at timestamptz NOT NULL,CHECK(expires_at>granted_at));
CREATE INDEX active_consents_idx ON consents(tenant_id,grantee_organization_id,expires_at) WHERE revoked_at IS NULL;
CREATE TABLE document_share_grants(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),document_id uuid NOT NULL REFERENCES documents(id),issued_to_customer_id uuid REFERENCES customers(id),issued_to_organization_id uuid REFERENCES organizations(id),token_hash char(64) NOT NULL,expires_at timestamptz NOT NULL,max_downloads integer NOT NULL CHECK(max_downloads>=1),download_count integer NOT NULL DEFAULT 0 CHECK(download_count>=0 AND download_count<=max_downloads),revoked_at timestamptz,created_by uuid NOT NULL,created_at timestamptz NOT NULL,UNIQUE(tenant_id,token_hash),CHECK(issued_to_customer_id IS NOT NULL OR issued_to_organization_id IS NOT NULL));
CREATE TABLE disclosure_logs(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),document_id uuid NOT NULL REFERENCES documents(id),actor_id uuid NOT NULL,recipient_type text NOT NULL CHECK(recipient_type IN('customer','organization')),recipient_id uuid NOT NULL,action text NOT NULL CHECK(action IN('view','download')),legal_basis text NOT NULL CHECK(legal_basis IN('consent','contract','legal_obligation')),consent_id uuid REFERENCES consents(id),occurred_at timestamptz NOT NULL,ip_hash char(64));
DO $$ DECLARE n text;BEGIN FOREACH n IN ARRAY ARRAY['documents','consents','document_share_grants','disclosure_logs'] LOOP EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY',n);EXECUTE format('ALTER TABLE %I FORCE ROW LEVEL SECURITY',n);EXECUTE format('CREATE POLICY tenant_isolation ON %I USING (tenant_id=current_setting(''app.tenant_id'',true)::uuid) WITH CHECK (tenant_id=current_setting(''app.tenant_id'',true)::uuid)',n);END LOOP;END $$;
